CREATE TABLE IF NOT EXISTS analytics_events (tenant_id UInt64, subject_account_id UInt64, media_item_id UInt64, event_date Date DEFAULT toDate(event_time), event_time DateTime64(3, 'UTC'), event_type LowCardinality(String), related_account_username String, confidence_score Float32, source_name LowCardinality(String), payload_json String) ENGINE = MergeTree PARTITION BY toYYYYMM(event_date) ORDER BY (tenant_id, subject_account_id, event_type, event_time);
